const SERVER_CODE_PATTERNS = [
  /createServer/,
  /\.listen\s*\(/,
  /http\.createServer/,
  /https\.createServer/,
  /express\s*\(\s*\)/,
  /fastify\s*\(\s*\)/,
  /new\s+Hono\s*\(\s*\)/,
  /new\s+Elysia\s*\(\s*\)/,
  /Koa\s*\(\s*\)/,
  /nest\s*\(\s*\)/,
  /app\.listen\s*\(/,
  /server\.listen\s*\(/,
  /Deno\.serve/,
  /Bun\.serve/,
  /serve\s*\(/,
];

const TUTORIAL_RX = /\b(learn|tutorial|course|workshop|playground|cheatsheet|starter\s*kit|boilerplate|template\s*repo|example\s*repo|sample)\b/i;

const SERVER_FRAMEWORK_RX = /^(express|fastify|koa|hapi|hono|elysia|nest|nestjs|sails|meteor|feathers|loopback)\b/i;

const DEPLOY_CONFIG_FILES = ['vercel.json', 'netlify.toml', '_headers', 'wrangler.toml'];

const LIBRARY_KEYWORDS = new Set(['library', 'plugin', 'sdk', 'toolkit', 'middleware', 'util', 'utils', 'helper', 'module', 'framework']);

function isTutorialRepo(packageJson, tree) {
  if (!packageJson) return false;
  const text = [
    packageJson.name,
    packageJson.description,
    ...(packageJson.keywords || []),
  ].filter(Boolean).join(' ');
  if (TUTORIAL_RX.test(text)) return true;

  const topDirs = new Set();
  for (const p of tree) {
    const top = p.split('/')[0];
    if (top && !top.startsWith('.') && top !== 'package.json' && top !== 'README.md' && top !== 'LICENSE') {
      topDirs.add(top);
    }
  }
  const tutorialDirs = [...topDirs].filter(d => /^(examples?|demos?|tutorials?|learn|playground|starters?|templates?|chapters?|lessons?)$/.test(d));
  if (tutorialDirs.length > 0 && topDirs.size <= 4 && !tree.some(p => /^(src|app|lib|packages)\/[^/]+/.test(p))) {
    return true;
  }
  return false;
}

function hasServerFrameworkDep(packageJson) {
  if (!packageJson) return false;
  const deps = { ...(packageJson.dependencies || {}), ...(packageJson.devDependencies || {}), ...(packageJson.peerDependencies || {}) };
  return Object.keys(deps).some(d => SERVER_FRAMEWORK_RX.test(d));
}

function isFrameworkOrLibrarySource(packageJson, tree) {
  if (!packageJson) return false;

  const scripts = packageJson.scripts || {};
  const hasDeployScript = !!(scripts.start || scripts.serve || scripts['start:prod'] || scripts.preview);
  const hasWorkspaces = !!(packageJson.workspaces);
  const hasPackagesDir = tree.some(p => /^(packages|pkg)\/[^/]+\//.test(p));
  const hasAppsDir = tree.some(p => /^(apps|sites|services|clients|studio|web|api|server)\/[^/]+\//.test(p));
  const isPrivate = packageJson.private === true;
  const hasDeployConfig = tree.some(p => DEPLOY_CONFIG_FILES.some(f => p === f || p.endsWith(`/${f}`)) || /^(Dockerfile|docker-compose|fly\.toml|render\.yaml|railway\.toml|app\.yaml|Procfile)/.test(p));

  if ((hasWorkspaces || hasPackagesDir) && !hasAppsDir && isPrivate && !hasDeployScript && !hasDeployConfig) {
    return true;
  }

  const isPublished = !!(packageJson.main || packageJson.module || packageJson.exports || packageJson.types || packageJson.typings);
  const hasServerEntry = tree.some(p => /^(server|listen|worker)\.(js|ts|mjs|cjs)$/.test(p));
  const hasApiDir = tree.some(p => /(^|\/)api\//.test(p));
  const hasLibOrSrc = tree.some(p => /^(lib|src)\/[^/]+/.test(p));
  const isExample = TUTORIAL_RX.test(packageJson.name || '');
  const keywords = (packageJson.keywords || []).map(k => k.toLowerCase());
  const hasLibKeyword = keywords.some(k => LIBRARY_KEYWORDS.has(k));
  const hasBin = !!(packageJson.bin);
  const hasServerFw = hasServerFrameworkDep(packageJson);

  if (isPublished && !hasDeployScript && !hasServerEntry && !hasApiDir && !hasDeployConfig && !isExample && !hasServerFw && (hasLibOrSrc || hasLibKeyword)) {
    return true;
  }

  if ((hasBin || hasLibKeyword) && !hasDeployScript && !hasServerEntry && !hasApiDir && !hasDeployConfig && !hasServerFw) {
    return true;
  }

  return false;
}

function hasCorsDep(packageJson) {
  if (!packageJson) return false;
  const deps = { ...(packageJson.dependencies || {}), ...(packageJson.devDependencies || {}), ...(packageJson.peerDependencies || {}) };
  return Object.keys(deps).some(k => {
    const base = k.includes('/') ? k.split('/').pop() : k;
    return base.toLowerCase().includes('cors');
  });
}

function isApiRouteFile(p) {
  if (!/\.(js|ts|jsx|tsx|mjs|cjs|mts|cts)$/.test(p)) return false;
  if (/(^|\/)node_modules\//.test(p)) return false;
  if (/(^|\/)(test|tests|__tests__|spec|example|examples|fixtures|fixture|mock|mocks|docs|playground|storybook|e2e|cypress|vitest|jest|coverage|\.tmp|\.next|out|dist|build)\//i.test(p)) return false;
  return /(^|\/)api\//.test(p) ||
         /(^|\/)pages\/api\//.test(p) ||
         /(^|\/)app\/api\//.test(p) ||
         /(^|\/)src\/pages\/api\//.test(p) ||
         /(^|\/)src\/app\/api\//.test(p) ||
         /(^|\/)server\/api\//.test(p) ||
         /(^|\/)functions\//.test(p) ||
         /(^|\/)workers\//.test(p) ||
         /(^|\/)controllers\//.test(p) ||
         /(^|\/)routes\/api\//.test(p) ||
         /\+server\.(ts|js|mjs|cjs)$/.test(p);
}

function isServerEntryFileByPath(p) {
  if (!/\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/.test(p)) return false;
  if (/(^|\/)node_modules\//.test(p)) return false;
  if (/(^|\/)(test|tests|__tests__|spec|example|examples|fixtures|fixture|mock|mocks|docs|playground|storybook|e2e|cypress|vitest|jest|coverage|\.tmp|\.next|out|dist|build)\//i.test(p)) return false;
  const b = p.slice(p.lastIndexOf('/') + 1);
  return /^(server|listen|worker|main)\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/.test(b);
}

function isRouteFile(p) {
  if (!/\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/.test(p)) return false;
  if (/(^|\/)node_modules\//.test(p)) return false;
  if (/(^|\/)(test|tests|__tests__|spec|example|examples|fixtures|fixture|mock|mocks|docs|playground|storybook|e2e|cypress|vitest|jest|coverage|\.tmp|\.next|out|dist|build)\//i.test(p)) return false;
  return /(^|\/)routes\/[^/]+\.(js|ts|mjs|cjs)$/.test(p);
}

async function rootFileLooksLikeServer(files, tree) {
  const rootFiles = tree.filter(p => !p.includes('/') && /^(app|index|server|main)\.(js|ts|mjs|cjs)$/.test(p));
  for (const p of rootFiles) {
    const content = await files.get(p);
    if (!content) continue;
    if (SERVER_CODE_PATTERNS.some(pat => pat.test(content))) return true;
  }
  return false;
}

export async function check(context) {
  const { tree, files, packageJson, repoType } = context;

  try {
    if (!tree || tree.length === 0 || repoType === 'empty') {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Empty repository', findings: [] };
    }

    if (isTutorialRepo(packageJson, tree)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Tutorial or example repository', findings: [] };
    }

    if (isFrameworkOrLibrarySource(packageJson, tree)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Library or framework source code — CORS not applicable', findings: [] };
    }

    if (hasCorsDep(packageJson)) {
      return { checkId, status: 'pass', confidence: 'high', message: 'CORS dependency found in package.json', findings: [] };
    }

    const subPkgPaths = tree.filter(p => /(^|\/)package\.json$/.test(p) && !/node_modules/.test(p));
    for (const pkgPath of subPkgPaths.slice(0, 50)) {
      if (pkgPath === 'package.json') continue;
      const content = await files.get(pkgPath);
      if (!content) continue;
      try {
        const subPkg = JSON.parse(content);
        if (hasCorsDep(subPkg)) {
          return { checkId, status: 'pass', confidence: 'high', message: `CORS dependency found in ${pkgPath}`, findings: [{ file: pkgPath, issue: 'cors dependency detected' }] };
        }
      } catch {
        // ignore invalid JSON
      }
    }

    const deployConfigPaths = tree.filter(p => DEPLOY_CONFIG_FILES.some(f => p === f || p.endsWith(`/${f}`)));
    for (const cp of deployConfigPaths) {
      const content = await files.get(cp);
      if (!content) continue;
      if (/access-control-allow-origin/i.test(content) || /^[ \t]*cors\s*:/im.test(content)) {
        return { checkId, status: 'pass', confidence: 'high', message: `CORS configuration found in ${cp}`, findings: [{ file: cp, issue: 'CORS detected' }] };
      }
    }

    const candidates = [];
    for (const p of tree) {
      if (!/\.(js|ts|jsx|tsx|mjs|cjs|mts|cts)$/.test(p)) continue;
      if (/(^|\/)node_modules\//.test(p)) continue;
      if (/(^|\/)(test|tests|__tests__|spec|example|examples|fixtures|fixture|mock|mocks|docs|playground|storybook|e2e|cypress|vitest|jest|coverage|\.tmp|\.next|out|dist|build)\//i.test(p)) continue;

      let score = 0;
      const b = p.slice(p.lastIndexOf('/') + 1);

      if (/\.config\.(js|ts|mjs|cjs|mts|cts)$/.test(b)) score += 100;
      if (isApiRouteFile(p)) score += 90;
      if (isServerEntryFileByPath(p)) score += 80;
      if (/middleware\.(js|ts|mjs|cjs)$/.test(b)) score += 70;
      if (isRouteFile(p)) score += 60;
      if (/handler\.(js|ts|mjs|cjs)$/.test(b)) score += 50;
      if (/^src\//.test(p)) score += 10;

      if (score > 0) candidates.push({ path: p, score });
    }

    candidates.sort((a, b) => b.score - a.score);

    let foundServerCode = false;
    for (const { path } of candidates.slice(0, 100)) {
      const content = await files.get(path);
      if (!content) continue;

      for (const pat of CORS_PATTERNS) {
        if (pat.test(content)) {
